comment on table DIRKSPZM32.LVS_LTE_HIST is 'Transporteinheiten';
comment on column DIRKSPZM32.LVS_LTE_HIST."ABC" is 'A = Schnell B = Mittel C = Langsam';
comment on column DIRKSPZM32.LVS_LTE_HIST."AKT_INVENTUR_ID" is 'NULL = keine Inventur, ansonsten Inventur aktiv. ID aus LVS_INVENTUR';
comment on column DIRKSPZM32.LVS_LTE_HIST."ANZ_UML" is 'Anzahl der Umlagerungen ';
comment on column DIRKSPZM32.LVS_LTE_HIST."AUTO_DEPAL" is 'Automatisches depaletieren möglich? FALSE: nicht möglich, LAGE: Nur Lagenweise depaletieren möglich, LHM: LHM weise depaletierbar, NULL: Status ist unbekannt';
comment on column DIRKSPZM32.LVS_LTE_HIST."FIRMA_NR" is 'Firmennummer in der Datenbank';
